-- Note: this is a bootstrap file. It will be overwritten by generation.

-- | TypeScript code generator: converts Hydra type and term modules to TypeScript source code

module Hydra.TypeScript.Coder where

import qualified Hydra.Analysis as Analysis
import qualified Hydra.Constants as Constants
import qualified Hydra.Core as Core
import qualified Hydra.Environment as Environment
import qualified Hydra.Formatting as Formatting
import qualified Hydra.Lib.Lists as Lists
import qualified Hydra.Lib.Maps as Maps
import qualified Hydra.Lib.Strings as Strings
import qualified Hydra.Names as Names
import qualified Hydra.Packaging as Packaging
import qualified Hydra.Strip as Strip
import qualified Hydra.Util as Util
import qualified Hydra.Errors as Errors
import Prelude hiding (Enum, Ordering, decodeFloat, encodeFloat, fail, map, pure, sum)
import qualified Data.Map as M
import qualified Data.List as L
import qualified Data.Maybe as Y
import qualified Data.Set as S

data NsCtx = NsCtx {
  nsCtxFocus :: Packaging.Namespace,
  nsCtxAliases :: M.Map Packaging.Namespace String
}

moduleToTypeScript :: Packaging.Module -> [Packaging.Definition] -> t0 -> t1 -> Either Errors.Error (M.Map String String)
moduleToTypeScript mod defs _cx _g =
    let focusNs = Packaging.moduleNamespace mod
        declaredDeps = S.fromList (Packaging.moduleTermDependencies mod ++ Packaging.moduleTypeDependencies mod)
        scannedDeps = Analysis.definitionDependencyNamespaces defs
        partitioned = Environment.partitionDefinitions defs
        typeDefs = fst partitioned
        termDefs = snd partitioned
        typeAnnotationNss = S.fromList $ concatMap termDefTypeNamespaces termDefs
        typeDefNss = S.fromList $ concatMap typeDefNamespaces typeDefs
        depNss = S.delete focusNs (S.unions [declaredDeps, scannedDeps, typeAnnotationNss, typeDefNss])
        aliasMap = M.fromList [(ns, namespaceAlias ns) | ns <- S.toList depNss]
        ctx = NsCtx focusNs aliasMap
        typeItems = concatMap (encodeTypeDefinition ctx) typeDefs
        termItems = concatMap (encodeTermDefinition ctx) termDefs
        allItems = typeItems ++ termItems
        imports = generateImports focusNs aliasMap
        warningComment = tsLineComment Constants.warningAutoGeneratedFile
        moduleDoc = Y.maybe "" (\d -> tsDocComment d ++ "\n\n") (Packaging.moduleDescription mod)
        body = L.intercalate "\n\n" (filter (not . null) (warningComment : moduleDoc : imports : allItems))
        filePath = Names.namespaceToFilePath Util.CaseConventionCamel (Packaging.FileExtension "ts") (Packaging.moduleNamespace mod)
    in Right (Maps.singleton filePath (body ++ "\n"))

-- Namespace scanning for type annotations

termDefTypeNamespaces :: Packaging.TermDefinition -> [Packaging.Namespace]
termDefTypeNamespaces td =
    case Packaging.termDefinitionType td of
        Nothing -> []
        Just ts -> typeRefNamespaces (Core.typeSchemeType ts)

typeDefNamespaces :: Packaging.TypeDefinition -> [Packaging.Namespace]
typeDefNamespaces td =
    typeRefNamespaces (Core.typeSchemeType (Packaging.typeDefinitionType td))

typeRefNamespaces :: Core.Type -> [Packaging.Namespace]
typeRefNamespaces typ =
    case Strip.deannotateType typ of
      Core.TypeVariable (Core.Name n) ->
        case Packaging.qualifiedNameNamespace (Names.qualifyName (Core.Name n)) of
          Just ns -> [ns]
          Nothing -> []
      Core.TypeFunction (Core.FunctionType dom cod) ->
        typeRefNamespaces dom ++ typeRefNamespaces cod
      Core.TypeList t -> typeRefNamespaces t
      Core.TypeMaybe t -> typeRefNamespaces t
      Core.TypeSet t -> typeRefNamespaces t
      Core.TypeMap (Core.MapType k v) -> typeRefNamespaces k ++ typeRefNamespaces v
      Core.TypePair (Core.PairType a b) -> typeRefNamespaces a ++ typeRefNamespaces b
      Core.TypeEither (Core.EitherType l r) -> typeRefNamespaces l ++ typeRefNamespaces r
      Core.TypeApplication (Core.ApplicationType f a) -> typeRefNamespaces f ++ typeRefNamespaces a
      Core.TypeForall (Core.ForallType _ body) -> typeRefNamespaces body
      Core.TypeRecord fields -> concatMap (\ft -> typeRefNamespaces (Core.fieldTypeType ft)) fields
      Core.TypeUnion fields -> concatMap (\ft -> typeRefNamespaces (Core.fieldTypeType ft)) fields
      Core.TypeAnnotated at -> typeRefNamespaces (Core.annotatedTypeBody at)
      Core.TypeWrap t -> typeRefNamespaces t
      _ -> []

-- Import generation

generateImports :: Packaging.Namespace -> M.Map Packaging.Namespace String -> String
generateImports focusNs aliasMap =
    let sorted = L.sort [(alias, ns) | (ns, alias) <- M.toList aliasMap]
        toImport (alias, ns) = "import * as " ++ alias ++ " from \"" ++ relativeImportPath focusNs ns ++ "\";"
    in L.intercalate "\n" (L.map toImport sorted)

namespaceAlias :: Packaging.Namespace -> String
namespaceAlias ns =
    let parts = Strings.splitOn "." (Packaging.unNamespace ns)
        afterHydra = if length parts > 1 && head parts == "hydra" then tail parts else parts
    in concatMap Formatting.capitalize afterHydra

relativeImportPath :: Packaging.Namespace -> Packaging.Namespace -> String
relativeImportPath srcNs tgtNs =
    let srcParts = Strings.splitOn "." (Packaging.unNamespace srcNs)
        tgtParts = Strings.splitOn "." (Packaging.unNamespace tgtNs)
        srcDir = init srcParts
        tgtDir = init tgtParts
        tgtFile = last tgtParts
        commonLen = length (takeWhile id (zipWith (==) srcDir tgtDir))
        upCount = length srcDir - commonLen
        downParts = drop commonLen tgtDir
        ups = replicate upCount ".."
        relPath = if upCount > 0
                  then L.intercalate "/" (ups ++ downParts ++ [tgtFile])
                  else "./" ++ L.intercalate "/" (downParts ++ [tgtFile])
    in relPath ++ ".js"

-- Name resolution

resolveQualifiedName :: NsCtx -> String -> String
resolveQualifiedName ctx qualName =
    let qn = Names.qualifyName (Core.Name qualName)
        mns = Packaging.qualifiedNameNamespace qn
        local = Packaging.qualifiedNameLocal qn
    in case mns of
        Nothing -> sanitizeTsVar qualName
        Just ns | ns == nsCtxFocus ctx -> sanitizeTsVar local
                | otherwise -> case M.lookup ns (nsCtxAliases ctx) of
                    Just alias -> alias ++ "." ++ sanitizeTsVar local
                    Nothing -> sanitizeTsVar qualName

sanitizeTsName :: String -> String
sanitizeTsName = L.map (\c -> if c == '\'' then '_' else c)

sanitizeTsVar :: String -> String
sanitizeTsVar name =
    let cleaned = sanitizeTsName name
    in if S.member cleaned tsReservedWords then cleaned ++ "_" else cleaned

tsReservedWords :: S.Set String
tsReservedWords = S.fromList [
  "abstract", "arguments", "async", "await", "boolean", "break", "byte",
  "case", "catch", "char", "class", "const", "continue",
  "debugger", "default", "delete", "do", "double",
  "else", "enum", "eval", "export", "extends",
  "false", "final", "finally", "float", "for", "function",
  "goto", "if", "implements", "import", "in", "instanceof", "int", "interface",
  "let", "long", "native", "new", "null",
  "of", "package", "private", "protected", "public",
  "return", "short", "static", "super", "switch", "synchronized",
  "this", "throw", "throws", "transient", "true", "try", "typeof",
  "undefined", "var", "void", "volatile",
  "while", "with", "yield"]

-- Type definitions

encodeTypeDefinition :: NsCtx -> Packaging.TypeDefinition -> [String]
encodeTypeDefinition ctx td =
    let name = localName (Core.unName (Packaging.typeDefinitionName td))
        ts = Packaging.typeDefinitionType td
        schemeVars = Core.typeSchemeVariables ts
        typ = Core.typeSchemeType ts
        (forallVars, innerType) = collectForallParams typ
        tparams = if null schemeVars then forallVars else schemeVars
        genericSuffix = encodeTypeParams tparams
    in [encodeTypeDecl ctx name genericSuffix innerType]

collectForallParams :: Core.Type -> ([Core.Name], Core.Type)
collectForallParams t =
    case Strip.deannotateType t of
      Core.TypeForall ft ->
        let (rest, inner) = collectForallParams (Core.forallTypeBody ft)
        in (Core.forallTypeParameter ft : rest, inner)
      _ -> ([], t)

encodeTypeParams :: [Core.Name] -> String
encodeTypeParams [] = ""
encodeTypeParams params = "<" ++ L.intercalate ", " (L.map (\(Core.Name n) -> sanitizeTsName n) params) ++ ">"

encodeTypeDecl :: NsCtx -> String -> String -> Core.Type -> String
encodeTypeDecl ctx name generics typ =
    case Strip.deannotateType typ of
      Core.TypeRecord fields ->
        let fieldLines = L.map (encodeFieldType ctx) fields
        in "export interface " ++ name ++ generics ++ " {\n" ++
           L.intercalate "\n" (L.map ("  " ++) fieldLines) ++ "\n}"

      Core.TypeUnion fields ->
        let variants = L.map (encodeUnionVariant ctx) fields
        in "export type " ++ name ++ generics ++ " =\n  | " ++ L.intercalate "\n  | " variants ++ ";"

      Core.TypeWrap innerType ->
        "export type " ++ name ++ generics ++ " = " ++ encodeTypeRef ctx innerType ++ " & { readonly __brand: \"" ++ name ++ "\" };"

      _ ->
        "export type " ++ name ++ generics ++ " = " ++ encodeTypeRef ctx typ ++ ";"

encodeFieldType :: NsCtx -> Core.FieldType -> String
encodeFieldType ctx ft =
    let fname = sanitizeTsName (Formatting.decapitalize (Core.unName (Core.fieldTypeName ft)))
        ftype = encodeTypeRef ctx (Core.fieldTypeType ft)
    in "readonly " ++ fname ++ ": " ++ ftype ++ ";"

encodeUnionVariant :: NsCtx -> Core.FieldType -> String
encodeUnionVariant ctx ft =
    let fname = Formatting.decapitalize (Core.unName (Core.fieldTypeName ft))
        ftype = Core.fieldTypeType ft
        stripped = Strip.deannotateType ftype
    in case stripped of
      Core.TypeUnit -> "{ readonly tag: \"" ++ fname ++ "\" }"
      Core.TypeRecord [] -> "{ readonly tag: \"" ++ fname ++ "\" }"
      _ -> "{ readonly tag: \"" ++ fname ++ "\"; readonly value: " ++ encodeTypeRef ctx ftype ++ " }"

-- Type references

encodeTypeRef :: NsCtx -> Core.Type -> String
encodeTypeRef ctx typ =
    case Strip.deannotateType typ of
      Core.TypeLiteral lt -> encodeLiteralType lt
      Core.TypeList inner -> "ReadonlyArray<" ++ encodeTypeRef ctx inner ++ ">"
      Core.TypeMaybe inner -> encodeTypeRef ctx inner ++ " | null"
      Core.TypeMap (Core.MapType k v) -> "ReadonlyMap<" ++ encodeTypeRef ctx k ++ ", " ++ encodeTypeRef ctx v ++ ">"
      Core.TypeSet inner -> "ReadonlySet<" ++ encodeTypeRef ctx inner ++ ">"
      Core.TypePair (Core.PairType a b) -> "readonly [" ++ encodeTypeRef ctx a ++ ", " ++ encodeTypeRef ctx b ++ "]"
      Core.TypeFunction (Core.FunctionType dom cod) -> "((x: " ++ encodeTypeRef ctx dom ++ ") => " ++ encodeTypeRef ctx cod ++ ")"
      Core.TypeVariable (Core.Name n) -> resolveQualifiedName ctx n
      Core.TypeUnit -> "void"
      Core.TypeWrap innerType -> encodeTypeRef ctx innerType
      Core.TypeEither (Core.EitherType l r) -> encodeTypeRef ctx l ++ " | " ++ encodeTypeRef ctx r
      Core.TypeRecord fields ->
        "{ " ++ L.intercalate "; " (L.map (\ft ->
          "readonly " ++ sanitizeTsName (Formatting.decapitalize (Core.unName (Core.fieldTypeName ft))) ++ ": " ++ encodeTypeRef ctx (Core.fieldTypeType ft)) fields) ++ " }"
      Core.TypeUnion _ -> "unknown"
      Core.TypeForall (Core.ForallType (Core.Name _v) body) -> encodeTypeRef ctx body
      Core.TypeApplication _ -> encodeTypeApplication ctx typ
      _ -> "unknown"

encodeTypeApplication :: NsCtx -> Core.Type -> String
encodeTypeApplication ctx typ =
    let (base, args) = collectTypeArgs typ
    in encodeTypeRef ctx base ++ "<" ++ L.intercalate ", " (L.map (encodeTypeRef ctx) args) ++ ">"

collectTypeArgs :: Core.Type -> (Core.Type, [Core.Type])
collectTypeArgs typ =
    case Strip.deannotateType typ of
      Core.TypeApplication (Core.ApplicationType f a) ->
        let (base, args) = collectTypeArgs f
        in (base, args ++ [a])
      _ -> (typ, [])

encodeLiteralType :: Core.LiteralType -> String
encodeLiteralType lt =
    case lt of
      Core.LiteralTypeBoolean -> "boolean"
      Core.LiteralTypeString -> "string"
      Core.LiteralTypeBinary -> "Uint8Array"
      Core.LiteralTypeFloat ft -> case ft of
        Core.FloatTypeFloat32 -> "number"
        Core.FloatTypeFloat64 -> "number"
        Core.FloatTypeBigfloat -> "number"
      Core.LiteralTypeInteger it -> case it of
        Core.IntegerTypeBigint -> "bigint"
        Core.IntegerTypeInt64 -> "bigint"
        Core.IntegerTypeUint64 -> "bigint"
        _ -> "number"

-- Term definitions

encodeTermDefinition :: NsCtx -> Packaging.TermDefinition -> [String]
encodeTermDefinition ctx td =
    let name = sanitizeTsVar (Formatting.decapitalize (localName (Core.unName (Packaging.termDefinitionName td))))
        term = Packaging.termDefinitionTerm td
        mtype = Packaging.termDefinitionType td
        tparams = Y.maybe [] Core.typeSchemeVariables mtype
        genericSuffix = encodeTypeParams tparams
    in [encodeTerm ctx name genericSuffix mtype term]

encodeTerm :: NsCtx -> String -> String -> Maybe Core.TypeScheme -> Core.Term -> String
encodeTerm ctx name generics mtype term =
    case stripTypeAbstractions term of
      Core.TermLambda lam ->
        let paramName = sanitizeTsVar (Core.unName (Core.lambdaParameter lam))
            paramType = Y.maybe "" (\t -> ": " ++ encodeTypeRef ctx t) (Core.lambdaDomain lam)
            body = encodeTermExpr ctx (Core.lambdaBody lam)
            returnType = Y.maybe "" (\ts ->
                ": " ++ encodeTypeRef ctx (stripOneFunctionType (Core.typeSchemeType ts))
                ) mtype
        in "export function " ++ name ++ generics ++ "(" ++ paramName ++ paramType ++ ")" ++ returnType ++ " {\n  return " ++ body ++ ";\n}"
      _ ->
        let typeAnn = Y.maybe "" (\ts -> ": " ++ encodeTypeRef ctx (Core.typeSchemeType ts)) mtype
        in "export const " ++ name ++ typeAnn ++ " = " ++ encodeTermExpr ctx term ++ ";"

stripTypeAbstractions :: Core.Term -> Core.Term
stripTypeAbstractions term =
    case Strip.deannotateTerm term of
      Core.TermTypeLambda tl -> stripTypeAbstractions (Core.typeLambdaBody tl)
      other -> other

stripOneFunctionType :: Core.Type -> Core.Type
stripOneFunctionType t =
    case Strip.deannotateType t of
      Core.TypeFunction ft -> Core.functionTypeCodomain ft
      Core.TypeForall ft -> stripOneFunctionType (Core.forallTypeBody ft)
      _ -> t

-- Term expressions

encodeTermExpr :: NsCtx -> Core.Term -> String
encodeTermExpr ctx term =
    case Strip.deannotateTerm term of
      Core.TermLiteral lit -> encodeLiteral lit

      Core.TermList items -> "[" ++ L.intercalate ", " (L.map (encodeTermExpr ctx) items) ++ "]"

      Core.TermRecord rec ->
        let fields = Core.recordFields rec
        in "({\n" ++ L.intercalate ",\n" (L.map (\f ->
          "    " ++ sanitizeTsName (Formatting.decapitalize (Core.unName (Core.fieldName f))) ++ ": " ++ encodeTermExpr ctx (Core.fieldTerm f)) fields) ++ "\n  })"

      Core.TermInject inj ->
        let fieldName = Formatting.decapitalize (Core.unName (Core.fieldName (Core.injectionField inj)))
            fieldTerm = Core.fieldTerm (Core.injectionField inj)
        in case Strip.deannotateTerm fieldTerm of
          Core.TermUnit -> "({ tag: \"" ++ fieldName ++ "\" })"
          _ -> "({ tag: \"" ++ fieldName ++ "\", value: " ++ encodeTermExpr ctx fieldTerm ++ " })"

      Core.TermVariable (Core.Name n) -> resolveQualifiedName ctx n

      Core.TermApplication app ->
        let func = Core.applicationFunction app
            arg = Core.applicationArgument app
        in case Strip.deannotateTerm func of
          Core.TermCases cs -> encodeCaseApplication ctx cs arg
          _ -> encodeTermExpr ctx func ++ "(" ++ encodeTermExpr ctx arg ++ ")"

      Core.TermLambda lam ->
        let param = sanitizeTsVar (Core.unName (Core.lambdaParameter lam))
            paramType = Y.maybe "" (\t -> ": " ++ encodeTypeRef ctx t) (Core.lambdaDomain lam)
        in "((" ++ param ++ paramType ++ ") => " ++ encodeTermExpr ctx (Core.lambdaBody lam) ++ ")"

      Core.TermUnit -> "undefined"

      Core.TermMaybe m -> case m of
        Nothing -> "null"
        Just v -> encodeTermExpr ctx v

      Core.TermPair (a, b) -> "[" ++ encodeTermExpr ctx a ++ ", " ++ encodeTermExpr ctx b ++ "]"

      Core.TermCases cs -> encodeCaseFunction ctx cs

      Core.TermEither e -> case e of
        Left v  -> "({ tag: \"left\", value: " ++ encodeTermExpr ctx v ++ " })"
        Right v -> "({ tag: \"right\", value: " ++ encodeTermExpr ctx v ++ " })"

      Core.TermLet letExpr ->
        let bindings = Core.letBindings letExpr
            body = Core.letBody letExpr
            bindingLines = L.map (\b ->
              "  const " ++ sanitizeTsVar (Core.unName (Core.bindingName b)) ++ " = " ++ encodeTermExpr ctx (Core.bindingTerm b) ++ ";") bindings
        in "(() => {\n" ++ L.intercalate "\n" bindingLines ++ "\n  return " ++ encodeTermExpr ctx body ++ ";\n})()"

      Core.TermMap entries ->
        let pairs = M.toList entries
        in "new Map([" ++ L.intercalate ", " (L.map (\(k,v) ->
          "[" ++ encodeTermExpr ctx k ++ ", " ++ encodeTermExpr ctx v ++ "]") pairs) ++ "])"

      Core.TermSet elements ->
        let elems = S.toList elements
        in "new Set([" ++ L.intercalate ", " (L.map (encodeTermExpr ctx) elems) ++ "])"

      Core.TermProject proj ->
        let fieldName = sanitizeTsName (Formatting.decapitalize (Core.unName (Core.projectionField proj)))
        in "((_x) => _x." ++ fieldName ++ ")"

      Core.TermUnwrap _ -> "((_x) => _x)"

      Core.TermWrap wrapped ->
        encodeTermExpr ctx (Core.wrappedTermBody wrapped)

      Core.TermTypeApplication ta ->
        encodeTermExpr ctx (Core.typeApplicationTermBody ta)

      Core.TermTypeLambda tl ->
        encodeTermExpr ctx (Core.typeLambdaBody tl)

      Core.TermAnnotated ann ->
        encodeTermExpr ctx (Core.annotatedTermBody ann)

      _ -> "undefined /* unsupported term */"

-- Case statement encoding

encodeCaseFunction :: NsCtx -> Core.CaseStatement -> String
encodeCaseFunction ctx cs =
    let cases = Core.caseStatementCases cs
        mdefault = Core.caseStatementDefault cs
        caseLines = L.map (\f ->
          let fname = Formatting.decapitalize (Core.unName (Core.fieldName f))
              handler = encodeTermExpr ctx (Core.fieldTerm f)
          in "    case \"" ++ fname ++ "\": return " ++ handler ++ "((_x as any).value);") cases
        defaultLine = case mdefault of
          Just d  -> ["    default: return " ++ encodeTermExpr ctx d ++ "(_x);"]
          Nothing -> []
        allLines = caseLines ++ defaultLine
    in "((_x: any) => {\n  switch (_x.tag) {\n" ++ L.intercalate "\n" allLines ++ "\n  }\n})"

encodeCaseApplication :: NsCtx -> Core.CaseStatement -> Core.Term -> String
encodeCaseApplication ctx cs scrutinee =
    let cases = Core.caseStatementCases cs
        mdefault = Core.caseStatementDefault cs
        scrutineeExpr = encodeTermExpr ctx scrutinee
        caseLines = L.map (\f ->
          let fname = Formatting.decapitalize (Core.unName (Core.fieldName f))
              handler = encodeTermExpr ctx (Core.fieldTerm f)
          in "    case \"" ++ fname ++ "\": return " ++ handler ++ "((_m as any).value);") cases
        defaultLine = case mdefault of
          Just d  -> ["    default: return " ++ encodeTermExpr ctx d ++ "(_m);"]
          Nothing -> []
        allLines = caseLines ++ defaultLine
    in "(() => {\n  const _m = " ++ scrutineeExpr ++ ";\n  switch (_m.tag) {\n" ++ L.intercalate "\n" allLines ++ "\n  }\n})()"

-- Literals

encodeLiteral :: Core.Literal -> String
encodeLiteral lit =
    case lit of
      Core.LiteralBoolean b -> if b then "true" else "false"
      Core.LiteralString s -> "\"" ++ escapeString s ++ "\""
      Core.LiteralFloat fv -> case fv of
        Core.FloatValueFloat32 n -> show n
        Core.FloatValueFloat64 n -> show n
        Core.FloatValueBigfloat n -> show n
      Core.LiteralInteger iv -> case iv of
        Core.IntegerValueBigint n -> show n ++ "n"
        Core.IntegerValueInt8 n -> show n
        Core.IntegerValueInt16 n -> show n
        Core.IntegerValueInt32 n -> show n
        Core.IntegerValueInt64 n -> show n ++ "n"
        Core.IntegerValueUint8 n -> show n
        Core.IntegerValueUint16 n -> show n
        Core.IntegerValueUint32 n -> show n
        Core.IntegerValueUint64 n -> show n ++ "n"
      Core.LiteralBinary _ -> "new Uint8Array()"

-- Helpers

localName :: String -> String
localName = Formatting.capitalize . last . Strings.splitOn "."

escapeString :: String -> String
escapeString = concatMap escapeChar
  where
    escapeChar '\\' = "\\\\"
    escapeChar '"' = "\\\""
    escapeChar '\n' = "\\n"
    escapeChar '\r' = "\\r"
    escapeChar '\t' = "\\t"
    escapeChar c = [c]

tsLineComment :: String -> String
tsLineComment s = L.intercalate "\n" (L.map ("// " ++) (lines s))

tsDocComment :: String -> String
tsDocComment s = "/**\n" ++ L.intercalate "\n" (L.map (" * " ++) (lines s)) ++ "\n */"
